INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a7610db6abd6b79b439943e00f52b488e3892fdb97c11eb8c1670ed133bea091','Mid Semester','Basics of Electrical Engineering','EE24101','1','2024','Q.2(a)','Derive the expression for the equivalent resistance of three resistors connected in parallel and show that the total conductance is the sum of individual conductances.','\\text{Derive the expression for the equivalent resistance of three resistors connected in parallel.}','1. Assumption: Three resistors R1, R2, and R3 are connected in parallel to a voltage source V. Each resistor experiences the same voltage V, while the total current I splits into branch currents I1, I2, and I3. 2. Law: Kirchhoff\'s Current Law (KCL) states that the sum of currents entering a node equals the sum of currents leaving it. Thus, I = I1 + I2 + I3. 3. Ohm\'s Law states I = V/R, so I1 = V/R1, I2 = V/R2, and I3 = V/R3. 4. Substituting these into the KCL equation: V/Req = V/R1 + V/R2 + V/R3. 5. Factoring out V, we get 1/Req = 1/R1 + 1/R2 + 1/R3. 6. Conductance G is defined as G = 1/R. Substituting this, we obtain G_total = G1 + G2 + G3.','\\text{Consider three resistors } R_1, R_2, \\text{ and } R_3 \\text{ connected in parallel across a voltage source } V. \\text{ By Kirchhoff\'s Current Law (KCL):} \\\\ I_{total} = I_1 + I_2 + I_3 \\\\ \\text{Using Ohm\'s Law } (I = V/R): \\\\ \\frac{V}{R_{eq}} = \\frac{V}{R_1} + \\frac{V}{R_2} + \\frac{V}{R_3} \\\\ \\text{Dividing both sides by } V: \\\\ \\frac{1}{R_{eq}} = \\frac{1}{R_1} + \\frac{1}{R_2} + \\frac{1}{R_3} \\\\ \\text{Since conductance } G = 1/R, \\text{ we define } G_{eq} = 1/R_{eq}, G_1 = 1/R_1, G_2 = 1/R_2, \\text{ and } G_3 = 1/R_3. \\\\ \\text{Therefore: } G_{eq} = G_1 + G_2 + G_3.','1/R_{eq} = 1/R_1 + 1/R_2 + 1/R_3; G_{total} = G_1 + G_2 + G_3','["DC Circuits", "Resistors"]','derivation','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('d4a2a0fa72886e813f2c30aa2769c24190f458ca944d33dcda0965480ad5486c','End Semester','Basics of Electrical Engineering','EE24101','2','2023','Q.4(b)','Derive the expression for the energy stored in a magnetic field of an inductor with inductance L and current I.','\\text{Derive the expression for the energy stored in a magnetic field of an inductor.}','To derive the energy stored in an inductor, we start from the power relationship in an electrical circuit. 1. The instantaneous power p(t) delivered to an inductor is given by the product of the voltage v(t) across it and the current i(t) flowing through it: p(t) = v(t) * i(t). 2. According to Faraday\'s Law of Induction for an inductor, the voltage across the inductor is v(t) = L * di/dt. 3. Substituting this into the power equation, we get p(t) = L * i(t) * di/dt. 4. Since power is the rate of change of energy (p = dW/dt), we can write dW = L * i * di. 5. To find the total energy W stored as the current increases from 0 to I, we integrate both sides: W = integral from 0 to I of (L * i * di). 6. Evaluating the integral yields W = 1/2 * L * I^2.','The instantaneous power p(t) supplied to an inductor is defined as p(t) = v(t)i(t). By the definition of an ideal inductor, v(t) = L \\frac{di}{dt}. Substituting this into the power equation: p(t) = L i(t) \\frac{di}{dt}. Since p(t) = \\frac{dW}{dt}, we have dW = L i di. To find the total energy W stored when the current increases from 0 to I, we integrate: W = \\int_{0}^{W} dW\' = \\int_{0}^{I} L i\' di\'. Solving the integral: W = L \\left[ \\frac{1}{2} i\'^2 \\right]_{0}^{I}. Thus, W = \\frac{1}{2}LI^2.','W = 1/2 LI^2','["Inductance", "Magnetic Circuits"]','derivation','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e58b60fe5204c333cbe990aa78d6be9bdcce45c09943efaaa8e8e8ca7e70a69d','Mid Semester','Basics of Electrical Engineering','EE24101','3','2024','Q.3(b)','For a series R-L-C circuit, derive the condition for resonance and find the expression for resonant frequency.','\\text{Derive the condition for resonance and resonant frequency for a series R-L-C circuit.}','1. Define the circuit impedance: A series R-L-C circuit has a total complex impedance Z = R + j(XL - XC), where XL = omega*L and XC = 1/(omega*C). 2. Define resonance: Resonance occurs when the imaginary part of the impedance is zero, meaning the voltage and current are in phase. 3. Set the imaginary part to zero: omega*L - 1/(omega*C) = 0. 4. Solve for omega: omega*L = 1/(omega*C) implies omega^2 = 1/(LC). 5. Calculate resonant frequency: Since omega = 2*pi*f, solve for f. The resonant frequency is f = 1 / (2 * pi * sqrt(LC)).','Step 1: The total impedance Z of a series R-L-C circuit is given by Z = R + j(X_L - X_C), where X_L = \\omega L and X_C = \\frac{1}{\\omega C}. Step 2: Resonance occurs when the reactive part of the impedance is zero (unity power factor condition), i.e., Im(Z) = 0. Step 3: Setting the imaginary part to zero yields \\omega L - \\frac{1}{\\omega C} = 0. Step 4: Rearranging for \\omega: \\omega^2 = \\frac{1}{LC} \\implies \\omega_0 = \\frac{1}{\\sqrt{LC}}. Step 5: Since \\omega_0 = 2\\pi f_0, we obtain the resonant frequency: f_0 = \\frac{1}{2\\pi \\sqrt{LC}}.','f_0 = \\frac{1}{2\\pi \\sqrt{LC}}','["AC Circuits", "Circuit Analysis", "Resonance"]','derivation','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('f68c3dc6faa2cdc24e2eac4277d11eb2f1432488af814b06ab4f0a4e9e799bb6','End Semester','Basics of Electrical Engineering','EE24101','4','2022','Q.5(a)','In a 3-phase balanced Delta (Δ) connection, derive the relationship between line current and phase current.','\\text{Derive the relationship between line current } (I_L) \\text{ and phase current } (I_{ph}) \\text{ for a balanced Delta connection.}','1. Assumptions: The system is a balanced 3-phase Delta-connected source/load. The phase currents have equal magnitude (I_ph) and are displaced by 120 degrees. Kirchhoff\'s Current Law (KCL) is applied at the nodes.\n2. In a Delta connection, each line is connected to the junction of two phases. Therefore, a line current is the difference between two phase currents.\n3. Let the phase currents be I_ab, I_bc, and I_ca. By KCL at the node connected to line A, the line current I_L = I_ab - I_ca.\n4. Representing these as phasors, if I_ab = I_ph ∠0°, then I_ca = I_ph ∠120°.\n5. Using vector subtraction: I_L = I_ph ∠0° - I_ph ∠120°.\n6. Expanding the phasors: I_L = I_ph(1 + j0) - I_ph(-0.5 + j0.866) = I_ph(1.5 - j0.866).\n7. Converting to polar form: Magnitude = I_ph * sqrt(1.5^2 + (-0.866)^2) = I_ph * sqrt(2.25 + 0.75) = sqrt(3) * I_ph.\n8. Thus, I_L = sqrt(3) * I_ph.','\\text{1. Assumptions: Balanced 3-phase } \\Delta \\text{ system, } I_{ab} = I_{ph}\\angle 0^{\\circ}, I_{bc} = I_{ph}\\angle -120^{\\circ}, I_{ca} = I_{ph}\\angle 120^{\\circ}. \\\\ \\text{2. Apply Kirchhoff\'s Current Law (KCL) at node A: } I_L = I_{ab} - I_{ca}. \\\\ \\text{3. Phasor subtraction: } I_L = I_{ph}(1\\angle 0^{\\circ} - 1\\angle 120^{\\circ}). \\\\ \\text{4. Convert to rectangular form: } I_L = I_{ph}[(1 + j0) - (-0.5 + j\\frac{\\sqrt{3}}{2})]. \\\\ \\text{5. Simplify: } I_L = I_{ph}(1.5 - j\\frac{\\sqrt{3}}{2}). \\\\ \\text{6. Calculate magnitude: } |I_L| = I_{ph}\\sqrt{(1.5)^2 + (-\\frac{\\sqrt{3}}{2})^2} = I_{ph}\\sqrt{2.25 + 0.75} = I_{ph}\\sqrt{3}. \\\\ \\text{7. Result: } I_L = \\sqrt{3}I_{ph}.','I_L = \\sqrt{3}I_{ph}','["Delta Connection", "Three-Phase Systems"]','derivation','1.0',0,1,'gemini-3.1-flash-lite','6','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('98b21fa6969db71a03bb88f5e938cf0f6f8b6b1cebcf5b3995d30e7480e5f173','End Semester','Basics of Electrical Engineering','EE24101','5','2024','Q.2(b)','Derive the expression for the force between two parallel current-carrying conductors.','\\text{Derive the expression for the force between two parallel current-carrying conductors.}','1. Consider two long, straight, parallel conductors separated by distance \'d\', carrying currents I1 and I2 in the same direction. 2. According to the Ampere-Maxwell law, current I1 creates a magnetic field B1 at the position of the second conductor. 3. Using Ampere\'s circuital law for an infinite wire, B1 = (μ0 * I1) / (2 * pi * d). 4. The magnetic field B1 is perpendicular to the second conductor. 5. The force on a segment of length L of the second conductor is given by the Lorentz force law: F = I2 * (L x B1). 6. Since B1 is perpendicular to the wire, the magnitude of the force is F = I2 * L * B1. 7. Substituting the expression for B1, we get F = I2 * L * (μ0 * I1) / (2 * pi * d). 8. The force per unit length is f = F / L = (μ0 * I1 * I2) / (2 * pi * d).','\\text{Step 1: Determine the magnetic field produced by conductor 1 at distance } d. \\text{ By Ampere\'s Law: } B_1 = \\frac{\\mu_0 I_1}{2 \\pi d}. \\text{ Step 2: Use the Lorentz force law for a current-carrying wire in a magnetic field: } \\vec{F} = I_2 \\vec{L} \\times \\vec{B}_1. \\text{ Step 3: Given } \\vec{L} \\perp \\vec{B}_1, \\text{ the magnitude is } F = I_2 L B_1. \\text{ Step 4: Substitute } B_1 \\text{ into the force equation: } F = I_2 L \\left( \\frac{\\mu_0 I_1}{2 \\pi d} \\right). \\text{ Step 5: Express force per unit length } f = \\frac{F}{L}: f = \\frac{\\mu_0 I_1 I_2}{2 \\pi d}.','f = \\frac{\\mu_0 I_1 I_2}{2 \\pi d}','["Magnetic Forces", "Magnetostatics"]','derivation','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);